#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    cmd = inp.get("command", "")

    # Block bare `pnpm test` but allow `pnpm test:ci`
    if cmd.strip().startswith("pnpm test") and "test:ci" not in cmd:
        print("Use `pnpm test:ci` instead — `pnpm test` opens an interactive watcher and won't return.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After editing Python files, run ruff check and surface violations."""
import json, subprocess, sys, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool not in ("Edit", "Write"):
        return 0

    inp = ev.get("tool_input") or {}
    file_path = inp.get("file_path", "")

    if not file_path.endswith(".py"):
        return 0

    # Run ruff check on the modified file
    try:
        result = subprocess.run(
            ["ruff", "check", file_path],
            capture_output=True,
            text=True,
            timeout=10,
            cwd=os.path.dirname(file_path) or "."
        )

        if result.returncode != 0:
            stderr_lines = result.stderr.strip().split("\n") if result.stderr.strip() else []
            stdout_lines = result.stdout.strip().split("\n") if result.stdout.strip() else []
            violations = stderr_lines + stdout_lines
            violations = [v for v in violations if v][:15]

            if violations:
                print(f"REQUIRED FOLLOW-UP: ruff check found {len(violations)} violation(s) in {file_path}:", file=sys.stderr)
                for v in violations:
                    print(f"  {v}", file=sys.stderr)
                print("Fix each violation, then proceed. Do not stop until clean.", file=sys.stderr)
                return 2
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/MultiEdit on a line that defines an exported identifier, grep
for callers and feed the list back to Claude so it can verify consistency."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+(\w+)"
)

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or [
        {"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}
    ]

    names: set = set()
    for e in edits:
        for s in (e.get("old_string", ""), e.get("new_string", "")):
            m = EXPORT_DEF.search(s)
            if m:
                names.add(m.group(1))

    if not names:
        return 0

    for name in names:
        try:
            r = subprocess.run(
                ["grep", "-rn", "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx", name, "."],
                capture_output=True, text=True, timeout=5,
            )
            hits = [l for l in r.stdout.splitlines() if l][:20]
            if hits:
                print(f"REQUIRED FOLLOW-UP: export `{name}` was edited. {len(hits)} references found:", file=sys.stderr)
                for h in hits:
                    print(f"  {h}", file=sys.stderr)
                print("Update each reference to match your change, then proceed. Do not stop.", file=sys.stderr)
                return 2
        except Exception:
            pass
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block Write/Edit/MultiEdit that hardcodes API keys, tokens, or passwords."""
import json, re, sys

# Common secret patterns (case-insensitive)
SECRET_PATTERNS = [
    (r'apiKey\s*[:=]\s*["\'](?!process\.env)[^"\']{8,}["\']', "hardcoded apiKey"),
    (r'api_key\s*[:=]\s*["\'](?!process\.env)[^"\']{8,}["\']', "hardcoded api_key"),
    (r'token\s*[:=]\s*["\'](?!process\.env)[^"\']{8,}["\']', "hardcoded token"),
    (r'password\s*[:=]\s*["\'](?!process\.env)[^"\']{3,}["\']', "hardcoded password"),
    (r'secret\s*[:=]\s*["\'](?!process\.env)[^"\']{8,}["\']', "hardcoded secret"),
    (r'bearer\s+["\'][a-zA-Z0-9_\-]{20,}["\']', "hardcoded bearer token"),
    (r'sk-[a-zA-Z0-9]{20,}', "OpenAI API key pattern (sk-...)"),
    (r'ghp_[a-zA-Z0-9]{36,}', "GitHub personal access token"),
    (r'glpat-[a-zA-Z0-9_\-]{20,}', "GitLab personal access token"),
]

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool not in ("Write", "Edit", "MultiEdit"):
        return 0

    inp = ev.get("tool_input") or {}

    # Collect all strings to scan
    texts = []
    if tool == "Write":
        texts.append(inp.get("content", ""))
    elif tool == "Edit":
        texts.append(inp.get("new_string", ""))
    elif tool == "MultiEdit":
        for edit in inp.get("edits") or []:
            texts.append(edit.get("new_string", ""))

    # Scan for secret patterns
    for text in texts:
        for pattern, desc in SECRET_PATTERNS:
            if re.search(pattern, text, re.IGNORECASE):
                print(f"BLOCKED: detected {desc} in source code.", file=sys.stderr)
                print("Secrets must come from process.env per CLAUDE.md.", file=sys.stderr)
                print(f"Read the secret from an environment variable instead.", file=sys.stderr)
                return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
import json
import sys
import re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    command = inp.get("command", "")

    # Only check git commit commands
    if not re.search(r'\bgit\s+commit\b', command):
        return 0

    # Extract commit message from -m flag using heredoc pattern
    # Matches: git commit -m "$(cat <<'EOF'\n...\nEOF\n)"
    heredoc_match = re.search(r'git\s+commit.*-m\s+"?\$\(cat\s*<<["\']?EOF["\']?\s*\n(.*?)\nEOF', command, re.DOTALL)

    if heredoc_match:
        message = heredoc_match.group(1).strip()
    else:
        # Fallback: simple -m "message" pattern
        simple_match = re.search(r'-m\s+["\']([^"\']+)["\']', command)
        if simple_match:
            message = simple_match.group(1).strip()
        else:
            # Can't extract message reliably; allow
            return 0

    # Split into subject and body
    lines = [line.strip() for line in message.split('\n') if line.strip()]

    if not lines:
        return 0

    subject = lines[0]

    # Check subject line length (conventional limit: 50-72 chars)
    if len(subject) > 72:
        print(f"BLOCKED: Commit subject line exceeds 72 characters ({len(subject)} chars). Use imperative mood, keep under 72 chars. Example: 'Refactor auth: extract token validation'", file=sys.stderr)
        return 2

    # Check for paragraph-style subjects (multiple sentences in subject)
    # Heuristic: subject contains ". " (period-space, indicating sentence break)
    if ". " in subject:
        print(f"BLOCKED: Commit subject appears to contain multiple sentences. Use a single imperative phrase. Example: 'Refactor auth: extract token validation' not 'This commit refactors... It extracts...'", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block WebFetch calls to staging-api.internal per CLAUDE.md project convention."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "WebFetch":
        return 0

    url = inp.get("url", "")
    if "staging-api.internal" in url:
        print("Blocked: CLAUDE.md prohibits calling staging-api.internal from agent sessions (shared environment, mutates state). Use recorded fixtures or the local mock server instead.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

